  1→// TM Robot TCP 클라이언트 (TMSCT + TMSVR)
  2→
  3→import * as net from 'net';
  4→import {
  5→  buildTmsctPacket,
  6→  buildTmsvrPacket,
  7→  parseTmsctResponse,
  8→  parseTmsvrResponse,
  9→  TmsctResponse,
 10→  TmsvrResponse,
 11→} from './packet';
 12→
 13→const DEFAULT_SCT_PORT = 5890;
 14→const DEFAULT_SVR_PORT = 5891;
 15→const RESPONSE_TIMEOUT = 10000; // 10초
 16→const MOTION_TAG_TIMEOUT = 1000; // QueueTag 응답 대기 1초
 17→const MOTION_POLL_TIMEOUT = 60000; // 좌표 폴링 최대 60초
 18→const MOTION_POLL_INTERVAL = 500; // 좌표 확인 간격 500ms
 19→const POSITION_TOLERANCE = 1.0; // 도착 판정 허용 오차 (도)
 20→
 21→export interface ConnectionInfo {
 22→  host: string;
 23→  sctPort: number;
 24→  svrPort: number;
 25→  sctConnected: boolean;
 26→  svrConnected: boolean;
 27→}
 28→
 29→export class TmClient {
 30→  private sctSocket: net.Socket | null = null;
 31→  private svrSocket: net.Socket | null = null;
 32→  private host = '';
 33→  private sctPort = DEFAULT_SCT_PORT;
 34→  private svrPort = DEFAULT_SVR_PORT;
 35→  private sctConnected = false;
 36→  private svrConnected = false;
 37→  private cmdId = 0;
 38→  private tagId = 0;
 39→
 40→  // 응답 대기용
 41→  private sctResolve: ((value: string) => void) | null = null;
 42→  private svrResolve: ((value: string) => void) | null = null;
 43→  private sctBuffer = '';
 44→  private svrBuffer = '';
 45→
 46→  // QueueTag: 응답 큐 (다중 응답 수신용)
 47→  private sctResponseQueue: string[] = [];
 48→  private sctQueueResolve: (() => void) | null = null;
 49→
 50→  /**
 51→   * 로봇 연결
 52→   */
 53→  async connect(host: string, sctPort?: number, svrPort?: number): Promise<string> {
 54→    this.host = host;
 55→    this.sctPort = sctPort ?? DEFAULT_SCT_PORT;
 56→    this.svrPort = svrPort ?? DEFAULT_SVR_PORT;
 57→
 58→    // 이미 연결된 상태면 즉시 리턴
 59→    if (this.sctConnected && this.svrConnected) {
 60→      return `이미 연결됨 (TMSCT:${this.sctPort}, TMSVR:${this.svrPort})`;
 61→    }
 62→
 63→    const results: string[] = [];
 64→
 65→    // TMSCT 연결 (미연결 시만)
 66→    if (!this.sctConnected) {
 67→      try {
 68→        await this.connectSocket('sct');
 69→        results.push(`TMSCT(${this.sctPort}) 연결 성공`);
 70→      } catch (err: any) {
 71→        results.push(`TMSCT(${this.sctPort}) 연결 실패: ${err.message}`);
 72→      }
 73→    } else {
 74→      results.push(`TMSCT(${this.sctPort}) 이미 연결됨`);
 75→    }
 76→
 77→    // TMSVR 연결 (미연결 시만)
 78→    if (!this.svrConnected) {
 79→      try {
 80→        await this.connectSocket('svr');
 81→        results.push(`TMSVR(${this.svrPort}) 연결 성공`);
 82→      } catch (err: any) {
 83→        results.push(`TMSVR(${this.svrPort}) 연결 실패: ${err.message}`);
 84→      }
 85→    } else {
 86→      results.push(`TMSVR(${this.svrPort}) 이미 연결됨`);
 87→    }
 88→
 89→    return results.join('\n');
 90→  }
 91→
 92→  private connectSocket(type: 'sct' | 'svr'): Promise<void> {
 93→    return new Promise((resolve, reject) => {
 94→      const port = type === 'sct' ? this.sctPort : this.svrPort;
 95→      const socket = new net.Socket();
 96→      const timeout = setTimeout(() => {
 97→        socket.destroy();
 98→        reject(new Error('연결 타임아웃'));
 99→      }, RESPONSE_TIMEOUT);
100→
101→      socket.connect(port, this.host, () => {
102→        clearTimeout(timeout);
103→        if (type === 'sct') {
104→          this.sctSocket = socket;
105→          this.sctConnected = true;
106→        } else {
107→          this.svrSocket = socket;
108→          this.svrConnected = true;
109→        }
110→        resolve();
111→      });
112→
113→      socket.on('data', (data) => {
114→        const str = data.toString();
115→        process.stderr.write(`[${type}] RECV: ${JSON.stringify(str)}\n`);
116→        if (type === 'sct') {
117→          this.sctBuffer += str;
118→          // 버퍼에 완전한 패킷이 있는지 반복 확인 (여러 패킷이 한번에 올 수 있음)
119→          while (this.sctBuffer.includes('\r\n')) {
120→            const idx = this.sctBuffer.indexOf('\r\n');
121→            const response = this.sctBuffer.substring(0, idx + 2);
122→            this.sctBuffer = this.sctBuffer.substring(idx + 2);
123→            if (this.sctResolve) {
124→              // sendScript용 (단일 응답)
125→              const resolve = this.sctResolve;
126→              this.sctResolve = null;
127→              resolve(response);
128→            } else {
129→              // sendMotionScript용 (다중 응답 → 큐에 적재)
130→              this.sctResponseQueue.push(response);
131→              process.stderr.write(`[SCT] 큐 적재 (${this.sctResponseQueue.length}개): ${JSON.stringify(response).substring(0, 100)}\n`);
132→              if (this.sctQueueResolve) {
133→                const notify = this.sctQueueResolve;
134→                this.sctQueueResolve = null;
135→                notify();
136→              }
137→            }
138→          }
139→        } else {
140→          this.svrBuffer += str;
141→          if (this.svrBuffer.includes('\r\n')) {
142→            if (this.svrResolve) {
143→              const response = this.svrBuffer;
144→              this.svrBuffer = '';
145→              this.svrResolve(response);
146→              this.svrResolve = null;
147→            } else {
148→              this.svrBuffer = '';
149→            }
150→          }
151→        }
152→      });
153→
154→      socket.on('error', (err) => {
155→        clearTimeout(timeout);
156→        if (type === 'sct') {
157→          this.sctConnected = false;
158→          this.sctSocket = null;
159→        } else {
160→          this.svrConnected = false;
161→          this.svrSocket = null;
162→        }
163→        reject(err);
164→      });
165→
166→      socket.on('close', () => {
167→        if (type === 'sct') {
168→          this.sctConnected = false;
169→          this.sctSocket = null;
170→        } else {
171→          this.svrConnected = false;
172→          this.svrSocket = null;
173→        }
174→      });
175→    });
176→  }
177→
178→  /**
179→   * 연결 해제
180→   */
181→  disconnect(): string {
182→    if (this.sctSocket) {
183→      this.sctSocket.destroy();
184→      this.sctSocket = null;
185→      this.sctConnected = false;
186→    }
187→    if (this.svrSocket) {
188→      this.svrSocket.destroy();
189→      this.svrSocket = null;
190→      this.svrConnected = false;
191→    }
192→    return '연결 해제 완료';
193→  }
194→
195→  /**
196→   * 연결 상태 조회
197→   */
198→  getStatus(): ConnectionInfo {
199→    return {
200→      host: this.host,
201→      sctPort: this.sctPort,
202→      svrPort: this.svrPort,
203→      sctConnected: this.sctConnected,
204→      svrConnected: this.svrConnected,
205→    };
206→  }
207→
208→  /**
209→   * TMSCT 명령 전송 (Listen Node 스크립트)
210→   */
211→  async sendScript(script: string): Promise<TmsctResponse> {
212→    if (!this.sctSocket || !this.sctConnected) {
213→      return {
214→        header: 'TMSCT',
215→        id: '',
216→        status: 'ERROR',
217→        message: 'TMSCT 미연결. tm_connect를 먼저 실행하세요.',
218→        raw: '',
219→      };
220→    }
221→
222→    const id = String(++this.cmdId).padStart(2, '0');
223→    const packet = buildTmsctPacket(id, script);
224→
225→    // 전송 전 버퍼 클리어
226→    this.sctBuffer = '';
227→
228→    return new Promise((resolve) => {
229→      const timeout = setTimeout(() => {
230→        this.sctResolve = null;
231→        resolve({
232→          header: 'TMSCT',
233→          id,
234→          status: 'TIMEOUT',
235→          message: `응답 타임아웃 (${RESPONSE_TIMEOUT/1000}초)`,
236→          raw: `SENT: ${JSON.stringify(packet)}`,
237→        });
238→      }, RESPONSE_TIMEOUT);
239→
240→      this.sctResolve = (raw: string) => {
241→        clearTimeout(timeout);
242→        resolve(parseTmsctResponse(raw));
243→      };
244→
245→      this.sctSocket!.write(packet);
246→    });
247→  }
248→
249→  /**
250→   * TMSVR 쿼리 전송 (상태 조회)
251→   */
252→  async sendSvrQuery(data: string, mode: number = 1): Promise<TmsvrResponse> {
253→    if (!this.svrSocket || !this.svrConnected) {
254→      return {
255→        header: 'TMSVR',
256→        mode: '',
257→        id: '',
258→        data: 'TMSVR 미연결. tm_connect를 먼저 실행하세요.',
259→        raw: '',
260→      };
261→    }
262→
263→    const id = String(++this.cmdId);
264→    const packet = buildTmsvrPacket(mode, id, data);
265→
266→    return new Promise((resolve) => {
267→      const timeout = setTimeout(() => {
268→        this.svrResolve = null;
269→        resolve({
270→          header: 'TMSVR',
271→          mode: String(mode),
272→          id,
273→          data: '응답 타임아웃 (5초)',
274→          raw: '',
275→        });
276→      }, RESPONSE_TIMEOUT);
277→
278→      this.svrResolve = (raw: string) => {
279→        clearTimeout(timeout);
280→        resolve(parseTmsvrResponse(raw));
281→      };
282→
283→      this.svrSocket!.write(packet);
284→    });
285→  }
286→
287→  /**
288→   * 응답 큐에서 하나 꺼내기 (없으면 도착할 때까지 대기)
289→   */
290→  private waitForQueuedResponse(timeoutMs: number): Promise<string | null> {
291→    return new Promise((resolve) => {
292→      // 이미 큐에 있으면 즉시 반환
293→      if (this.sctResponseQueue.length > 0) {
294→        resolve(this.sctResponseQueue.shift()!);
295→        return;
296→      }
297→      // 타임아웃
298→      const timer = setTimeout(() => {
299→        this.sctQueueResolve = null;
300→        resolve(null);
301→      }, timeoutMs);
302→      // 큐에 도착하면 알림
303→      this.sctQueueResolve = () => {
304→        clearTimeout(timer);
305→        resolve(this.sctResponseQueue.shift() ?? null);
306→      };
307→    });
308→  }
309→
310→  /**
311→   * 모션 명령 + QueueTag 전송 (도착 확인까지 대기)
312→   * 1) 모션명령\r\nQueueTag(N,1) 전송
313→   * 2) 첫 번째 응답: OK (명령 수락)
314→   * 3) 두 번째 응답: QueueTag 도달 (모션 완료)
315→   */
316→  async sendMotionScript(motionCmd: string, targetJoints?: number[]): Promise<TmsctResponse> {
317→    if (!this.sctSocket || !this.sctConnected) {
318→      return {
319→        header: 'TMSCT',
320→        id: '',
321→        status: 'ERROR',
322→        message: 'TMSCT 미연결. tm_connect를 먼저 실행하세요.',
323→        raw: '',
324→      };
325→    }
326→
327→    const id = String(++this.cmdId).padStart(2, '0');
328→    const tag = ++this.tagId;
329→    // 모션 명령 + QueueTag를 하나의 스크립트로 결합
330→    const script = `${motionCmd}\r\nQueueTag(${tag},1)`;
331→    const packet = buildTmsctPacket(id, script);
332→
333→    // 전송 전 큐/버퍼 클리어
334→    this.sctBuffer = '';
335→    this.sctResponseQueue = [];
336→    this.sctQueueResolve = null;
337→    this.sctResolve = null; // sendScript용 resolve도 클리어
338→
339→    // 패킷 전송
340→    this.sctSocket!.write(packet);
341→
342→    // 첫 번째 응답 대기 (명령 수락, 10초)
343→    const raw1 = await this.waitForQueuedResponse(RESPONSE_TIMEOUT);
344→    if (!raw1) {
345→      return {
346→        header: 'TMSCT', id, status: 'TIMEOUT',
347→        message: `응답 타임아웃 (${RESPONSE_TIMEOUT/1000}초)`,
348→        raw: `SENT: ${JSON.stringify(packet)}`,
349→      };
350→    }
351→
352→    const first = parseTmsctResponse(raw1);
353→    process.stderr.write(`[QueueTag] 1st: ${first.status} ${first.message}\n`);
354→
355→    if (first.status !== 'OK') {
356→      return first; // 명령 거부
357→    }
358→
359→    // 두 번째 응답 대기 (QueueTag 도달 = 모션 완료, 1초)
360→    const raw2 = await this.waitForQueuedResponse(MOTION_TAG_TIMEOUT);
361→    if (raw2) {
362→      const second = parseTmsctResponse(raw2);
363→      process.stderr.write(`[QueueTag] 2nd (tag ${tag}): ${second.status}\n`);
364→      return {
365→        header: 'TMSCT', id,
366→        status: second.status === 'OK' ? 'OK' : second.status,
367→        message: `모션 완료 (QueueTag ${tag})`,
368→        raw: raw2,
369→      };
370→    }
371→
372→    // QueueTag 1초 내 미도착 → 좌표 폴링으로 도착 확인
373→    process.stderr.write(`[QueueTag] tag ${tag} 1초 내 미응답, 좌표 폴링 시작\n`);
374→
375→    if (targetJoints && this.svrSocket && this.svrConnected) {
376→      const arrived = await this.pollUntilArrived(targetJoints);
377→      return {
378→        header: 'TMSCT', id, status: 'OK',
379→        message: arrived
380→          ? `모션 완료 (좌표 확인)`
381→          : `모션 완료 대기 타임아웃 (${MOTION_POLL_TIMEOUT/1000}초). 명령은 수락됨.`,
382→        raw: raw1,
383→      };
384→    }
385→
386→    return {
387→      header: 'TMSCT', id, status: 'OK',
388→      message: `명령 수락됨 (도착 확인 불가 — TMSVR 미연결)`,
389→      raw: raw1,
390→    };
391→  }
392→
393→  /**
394→   * TMSVR로 관절 좌표를 주기적으로 조회하여 목표 도달 확인
395→   */
396→  private async pollUntilArrived(targetJoints: number[]): Promise<boolean> {
397→    const startTime = Date.now();
398→    while (Date.now() - startTime < MOTION_POLL_TIMEOUT) {
399→      await new Promise(r => setTimeout(r, MOTION_POLL_INTERVAL));
400→      try {
401→        const posRes = await this.getPosition();
402→        // Robot_Link에서 관절값 파싱
403→        const joints = this.parseJointsFromSvr(posRes.data);
404→        if (joints) {
405→          const maxErr = Math.max(...joints.map((j, i) => Math.abs(j - targetJoints[i])));
406→          process.stderr.write(`[Poll] 현재: [${joints.map(j=>j.toFixed(1)).join(',')}] 목표: [${targetJoints.map(j=>j.toFixed(1)).join(',')}] 오차: ${maxErr.toFixed(2)}°\n`);
407→          if (maxErr <= POSITION_TOLERANCE) {
408→            process.stderr.write(`[Poll] 도착 확인!\n`);
409→            return true;
410→          }
411→        }
412→      } catch (err: any) {
413→        process.stderr.write(`[Poll] 조회 오류: ${err.message}\n`);
414→      }
415→    }
416→    process.stderr.write(`[Poll] 타임아웃 (${MOTION_POLL_TIMEOUT/1000}초)\n`);
417→    return false;
418→  }
419→
420→  /**
421→   * TMSVR 응답에서 관절 각도 배열 추출
422→   */
423→  private parseJointsFromSvr(data: string): number[] | null {
424→    try {
425→      // Robot_Link 값 찾기: "Robot_Link" : [j1, j2, j3, j4, j5, j6]
426→      const match = data.match(/Robot_Link[^[]*\[([^\]]+)\]/);
427→      if (match) {
428→        const values = match[1].split(',').map(s => parseFloat(s.trim()));
429→        if (values.length >= 6 && values.every(v => !isNaN(v))) {
430→          return values.slice(0, 6);
431→        }
432→      }
433→    } catch {}
434→    return null;
435→  }
