  1→// TM Robot 패킷 빌드 및 파싱
  2→
  3→export interface TmsctResponse {
  4→  header: string;
  5→  id: string;
  6→  status: string; // "OK" | "ERROR" 등
  7→  message: string;
  8→  raw: string;
  9→}
 10→
 11→export interface TmsvrResponse {
 12→  header: string;
 13→  mode: string;
 14→  id: string;
 15→  data: string;
 16→  raw: string;
