 51→// 진행 중인 CLI 프로세스 (비상정지 시 kill)
 52→let currentProcess: ChildProcess | null = null;
 53→
 54→/**
 55→ * Claude CLI를 spawn하여 stream-json 출력을 파싱
 56→ */
 57→function callClaude(
 58→  userInput: string,
 59→  sendEvent: (data: object) => void,
 60→  signal: AbortSignal
 61→): Promise<void> {
 62→  return new Promise((resolve, reject) => {
 63→    // 시스템 프롬프트를 임시 파일에 저장 (cmd.exe 인수 파싱 문제 회피)
 64→    const fs = require("fs");
 65→    const os = require("os");
 66→    const path = require("path");
 67→    const tmpDir = path.join(os.tmpdir(), "tm-agent");
 68→    if (!fs.existsSync(tmpDir)) fs.mkdirSync(tmpDir, { recursive: true });
 69→    const promptFile = path.join(tmpDir, "system-prompt.txt");
 70→    fs.writeFileSync(promptFile, SYSTEM_PROMPT, "utf-8");
 71→    const inputFile = path.join(tmpDir, "user-input.txt");
 72→    fs.writeFileSync(inputFile, userInput, "utf-8");
 73→
 74→    // PowerShell 스크립트로 실행 (cmd.exe 인수 파싱 문제 회피)
 75→    const psScript = `
 76→      Remove-Item Env:CLAUDECODE -ErrorAction SilentlyContinue
 77→      $prompt = Get-Content -Raw '${promptFile.replace(/'/g, "''")}'
 78→      $input = Get-Content -Raw '${inputFile.replace(/'/g, "''")}'
 79→      & claude.exe --print --output-format stream-json --verbose --model sonnet --system-prompt $prompt --allowedTools 'mcp__tm-robot__*' --max-turns 20 --no-session-persistence $input
 80→    `.trim();
 81→
 82→    console.log(`[CLI] PowerShell 경유 호출`);
 83→
 84→    const proc = spawn("powershell.exe", ["-NoProfile", "-Command", psScript], {
 85→      stdio: ["ignore", "pipe", "pipe"],
 86→      windowsHide: true,
 87→    });
 88→
 89→    currentProcess = proc;
 90→
 91→    let stderr = "";
 92→    let lastText = "";
 93→
 94→    // abort 시 프로세스 kill
 95→    const onAbort = () => {
 96→      if (proc.pid && !proc.killed) {
 97→        proc.kill("SIGTERM");
 98→      }
 99→    };
100→    signal.addEventListener("abort", onAbort, { once: true });
101→
102→    // stdout: stream-json 라인 파싱
103→    let buffer = "";
104→    proc.stdout?.on("data", (chunk: Buffer) => {
105→      buffer += chunk.toString("utf-8");
106→      const lines = buffer.split("\n");
107→      buffer = lines.pop() || "";
108→
109→      for (const line of lines) {
110→        const trimmed = line.trim();
111→        if (!trimmed) continue;
112→
113→        try {
114→          const event = JSON.parse(trimmed);
115→
116→          // assistant 텍스트 이벤트
117→          if (event.type === "assistant" && event.message?.content) {
118→            for (const block of event.message.content) {
119→              if (block.type === "text" && block.text) {
120→                if (block.text !== lastText) {
121→                  lastText = block.text;
122→                  sendEvent({ type: "text", content: block.text });
123→                }
124→              }
125→              if (block.type === "tool_use") {
126→                sendEvent({ type: "tool", name: block.name, status: "running" });
127→              }
128→            }
129→          }
130→
131→          // result 이벤트 (최종 응답)
132→          if (event.type === "result" && event.result) {
133→            let resultText = "";
134→            if (typeof event.result === "string") {
135→              resultText = event.result;
136→            } else if (event.result.content) {
137→              for (const block of event.result.content) {
138→                if (block.type === "text") {
139→                  resultText += block.text;
140→                }
141→              }
142→            }
143→            if (resultText && resultText !== lastText) {
144→              sendEvent({ type: "text", content: resultText });
145→            }
146→          }
147→
148→        } catch {
149→          // JSON 파싱 실패 무시
150→        }
151→      }
152→    });
153→
154→    proc.stderr?.on("data", (chunk: Buffer) => {
155→      const text = chunk.toString("utf-8");
156→      stderr += text;
157→      console.error(`[stderr] ${text.trimEnd()}`);
158→    });
159→
160→    proc.on("close", (code) => {
161→      currentProcess = null;
162→      signal.removeEventListener("abort", onAbort);
163→
164→      if (signal.aborted) {
165→        reject(new Error("취소됨"));
166→        return;
167→      }
168→
169→      if (code !== 0 && code !== null) {
170→        console.error(`[CLI] 종료 코드: ${code}`);
171→        reject(new Error(stderr.trim() || `CLI 종료 코드: ${code}`));
172→      } else {
173→        resolve();
174→      }
175→    });
176→
177→    proc.on("error", (err) => {
178→      currentProcess = null;
179→      reject(err);
180→    });
181→  });
182→}
